mapper.sql:
SELECT T.ID, T.USER_ID, T.VALUE_ID, T.ADD_TIME, T.IS_ATTENTION, T.TYPE_ID, U.NICKNAME FROM MALL_COLLECT T LEFT JOIN WX_USER U ON T.USER_ID = U.ID WHERE 1=1
AND T.ID = #{params.id}
AND T.NAME LIKE '%${params.name}%'

mapper.select:
select c.*,g.name, g.list_pic_url, g.goods_brief as goods_brief, g.retail_price as retail_price
from mall_collect c
left join mall_goods g on c.value_id = g.id
where 1 = 1

    and c.user_id = #{userId}


    and c.value_id = #{valueId}


    and c.type_id = #{typeId}



        order by ${sidx} ${order}


        order by c.id desc



    limit #{offset}, #{limit}
